"use client";

import { useEffect, useState } from "react";
import { Requisition } from "@/types";
import { getRequisitions } from "@/lib/requisitions";
import Link from "next/link";

export default function RequisitionsList() {
    const [requisitions, setRequisitions] = useState<Requisition[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        getRequisitions().then(data => {
            // Sort by newest first
            setRequisitions(data.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()));
            setLoading(false);
        });
    }, []);

    if (loading) return <div>Loading requests...</div>;

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', color: 'var(--primary)' }}>Purchase Requisitions</h1>
                <Link href="/dashboard/requisitions/new" className="btn btn-primary">
                    + New Request
                </Link>
            </div>

            {requisitions.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>No pending requests found.</p>
                </div>
            ) : (
                <div className="card" style={{ overflowX: 'auto', padding: 0 }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead style={{ backgroundColor: 'var(--background)', borderBottom: '1px solid var(--border)' }}>
                            <tr>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Date</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Req #</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Requester</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Vendor</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Total</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Status</th>
                            </tr>
                        </thead>
                        <tbody>
                            {requisitions.map((req) => (
                                <tr key={req.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                    <td style={{ padding: '1rem', fontSize: '0.9rem' }}>{req.createdAt.toLocaleDateString()}</td>
                                    <td style={{ padding: '1rem', fontWeight: 500 }}>#{req.id?.slice(-6).toUpperCase()}</td>
                                    <td style={{ padding: '1rem' }}>{req.requesterName}</td>
                                    <td style={{ padding: '1rem' }}>{req.vendorName || '-'}</td>
                                    <td style={{ padding: '1rem', fontWeight: 600 }}>${req.totalAmount.toFixed(2)}</td>
                                    <td style={{ padding: '1rem' }}>
                                        <span style={{
                                            padding: '0.25rem 0.5rem',
                                            borderRadius: '999px',
                                            fontSize: '0.75rem',
                                            backgroundColor: req.status === 'APPROVED' ? '#dcfce7' : req.status === 'PENDING' ? '#fef9c3' : '#fee2e2',
                                            color: req.status === 'APPROVED' ? '#166534' : req.status === 'PENDING' ? '#854d0e' : '#991b1b'
                                        }}>
                                            {req.status}
                                        </span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}
